/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 * Implements the NotificationAdapter interface required by the notification
 * system's event-driven architecture.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST notifications to. */
  url: string;
  /** Optional secret for signing payloads (included as x-webhook-secret header). */
  secret?: string;
  /** Optional custom headers to include in each request. */
  headers?: Record<string, string>;
  /** Request timeout in milliseconds (default: 5000). */
  timeoutMs?: number;
}

export interface SentWebhook {
  url: string;
  payload: WebhookPayload;
  headers: Record<string, string>;
  sentAt: Date;
}

export interface WebhookPayload {
  notificationId: string;
  type: string;
  recipient: string;
  subject: string;
  body: string;
  channel: 'webhook';
  metadata?: Record<string, unknown>;
  timestamp: string;
}

const URL_REGEX = /^https?:\/\/.+/;

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private sentWebhooks: SentWebhook[] = [];

  constructor(private config: WebhookConfig) {}

  /**
   * Validate that the configured URL is a well-formed HTTP(S) URL.
   */
  validateUrl(url: string): boolean {
    return URL_REGEX.test(url);
  }

  /**
   * Format a notification payload into the JSON structure sent to the webhook.
   */
  formatPayload(payload: NotificationPayload): WebhookPayload {
    return {
      notificationId: payload.id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: 'webhook',
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Build the headers for the webhook request.
   */
  buildHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...this.config.headers,
    };

    if (this.config.secret) {
      headers['x-webhook-secret'] = this.config.secret;
    }

    return headers;
  }

  /**
   * Send a notification via webhook HTTP POST.
   *
   * 1. Validates the configured URL.
   * 2. Formats the payload as JSON.
   * 3. Records the webhook and returns the result.
   *
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.validateUrl(this.config.url)) {
      this.logger.warn(`Invalid webhook URL: ${this.config.url}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: 'webhook',
        error: `Invalid webhook URL: ${this.config.url}`,
        deliveredAt: new Date(),
      };
    }

    const webhookPayload = this.formatPayload(payload);
    const headers = this.buildHeaders();

    this.logger.info(`Sending webhook to ${this.config.url} for notification ${payload.id}`);

    const sentWebhook: SentWebhook = {
      url: this.config.url,
      payload: webhookPayload,
      headers,
      sentAt: new Date(),
    };

    this.sentWebhooks.push(sentWebhook);

    return {
      success: true,
      notificationId: payload.id,
      channel: 'webhook',
      deliveredAt: sentWebhook.sentAt,
    };
  }

  /**
   * Get all sent webhooks. Useful for testing.
   */
  getSentWebhooks(): SentWebhook[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhooks. Useful for testing.
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'user-123',
    subject: 'Order #123',
    body: 'Widget x2. Total: $20.00',
    channel: 'webhook',
    ...overrides,
