    it('should reject invalid URLs', () => {
      expect(adapter.validateUrl('')).toBe(false);
      expect(adapter.validateUrl('not-a-url')).toBe(false);
      expect(adapter.validateUrl('ftp://example.com')).toBe(false);
      expect(adapter.validateUrl('https://')).toBe(false);
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook JSON', () => {
      const payload = makePayload();
      const formatted = adapter.formatPayload(payload);

      expect(formatted.notificationId).toBe('notif-0001');
      expect(formatted.type).toBe('order_confirmation');
      expect(formatted.recipient).toBe('user-123');
      expect(formatted.subject).toBe('Order #123');
