      expect(formatted.channel).toBe('webhook');
      expect(formatted.timestamp).toBeDefined();
    });

    it('should include metadata when present', () => {
      const payload = makePayload({ metadata: { orderId: 'ord-456' } });
      const formatted = adapter.formatPayload(payload);

      expect(formatted.metadata).toEqual({ orderId: 'ord-456' });
